request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task bbo:name "Data analysis" .
  ?task tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model bbo:name ?modelName .
  {
    ?participant1 a bboExt:Participant .
    ?participant1 tai:belongsTo ?choreo .
    ?participant1 bbo:name "The Client EHQ" .
  } UNION {
    ?participant2 a bboExt:Participant .
    ?participant2 tai:belongsTo ?choreo .
    ?participant2 bbo:name "The Client ELC" .
  }
  FILTER EXISTS { ?participant1 a bboExt:Participant . ?participant1 tai:belongsTo ?choreo . ?participant1 bbo:name "The Client EHQ" . }
  FILTER EXISTS { ?participant2 a bboExt:Participant . ?participant2 tai:belongsTo ?choreo . ?participant2 bbo:name "The Client ELC" . }
}
LIMIT 25
